prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?norm ?orig WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?norm . }
  OPTIONAL { ?model tai:originalId ?orig . }
  FILTER( (BOUND(?norm) && CONTAINS(LCASE(STR(?norm)), LCASE("4ccc3fd711004f519782ac92e58f6ddd")))
       || (BOUND(?orig) && CONTAINS(LCASE(STR(?orig)), LCASE("4ccc3fd711004f519782ac92e58f6ddd"))) )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?type ?choreo ?start ?startName ?pathCount WHERE {
  {
    SELECT ?task ?taskName ?type ?choreo WHERE {
      ?task tai:belongsTo ?choreo .
      ?choreo tai:belongsTo ?definitions .
      ?definitions tai:belongsTo ?model .
      FILTER(?model = <https://www.teamingai-project.eu/kg/model/sid_2258986a_c790_4708_ae4e_8dc02b7d122d>).

      ?task bbo:name ?taskName .
      FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("zustimmung"))).
      ?task a ?type .
    }
    LIMIT 25
  }

  OPTIONAL {
    ?choreo bboExt:isClosed ?closed .
  }

  ?choreo tai:belongsTo ?definitions2 .
  ?definitions2 tai:belongsTo ?model2 .
  FILTER(?model2 = <https://www.teamingai-project.eu/kg/model/sid_2258986a_c790_4708_ae4e_8dc02b7d122d>).

  ?start a bboExt:StartEvent .
  ?start tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  {
    SELECT (COUNT(*) AS ?pathCount) WHERE {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
  }
}
ORDER BY DESC(?pathCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT 
  (COUNT(DISTINCT ?start) AS ?totalStarts)
  (COUNT(DISTINCT ?startReach) AS ?startsReachingTask)
WHERE {
  BIND(<https://www.teamingai-project.eu/kg/model/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> AS ?model)

  {
    SELECT DISTINCT ?start WHERE {
      ?choreo tai:belongsTo ?defs .
      ?defs tai:belongsTo ?model .
      ?start a bboExt:StartEvent .
      ?start tai:belongsTo ?choreo .
    }
  }
  ?start a bboExt:StartEvent .

  BIND(
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-CAB5DD5D-BE94-4F7E-A643-81D13F16131A> AS ?task
  )

  OPTIONAL {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    BIND(?start AS ?startReach)
  }
}
